create or replace view public.manual_enhancer_status as with manual_rules as (select distinct on (er.month, er.store_id, er.brand, er.label, coalesce(er.pct, -999999), coalesce(er.flat_amount, -999999)) er.id as rule_id, er.month, er.store_id as rule_store_id, er.brand, er.make_pattern, er.label, er.pct, er.flat_amount from public.enhancer_rules er where er.metric = 'manual' order by er.month, er.store_id, er.brand, er.label, coalesce(er.pct, -999999), coalesce(er.flat_amount, -999999), er.id), assigned as (select mr.rule_id, mr.month, coalesce(mr.rule_store_id, brc.store_id, e.store_id) as store_id, mr.brand, mr.label, mr.pct, mr.flat_amount, e.id as employee_id, e.display_name as rep, s.name as dealer from manual_rules mr join public.brand_rep_classifications brc on brc.brand = mr.brand and brc.active and (mr.rule_store_id is null or brc.store_id = mr.rule_store_id) join public.employees e on e.id = brc.employee_id left join public.stores s on s.id = coalesce(mr.rule_store_id, brc.store_id, e.store_id)), approved_existing as (select distinct er.id as rule_id, er.month, coalesce(er.store_id, a.store_id, e.store_id) as store_id, er.brand, er.label, er.pct, er.flat_amount, e.id as employee_id, e.display_name as rep, s.name as dealer from public.adjustments a join public.enhancer_rules er on er.id = a.rule_id and er.metric = 'manual' join public.employees e on e.id = a.employee_id left join public.stores s on s.id = coalesce(er.store_id, a.store_id, e.store_id) where a.category = 'enhancer'), review_reps as (select * from assigned union select * from approved_existing), rep_metrics as (select rr.rule_id, rr.month, rr.store_id, rr.brand, rr.label, rr.pct, rr.flat_amount, rr.employee_id, rr.rep, rr.dealer, coalesce(sum(case when d.make ilike mr.make_pattern then coalesce(d.front_gross, 0) * dp.split_pct else 0 end), 0) as brand_front_gross, coalesce(sum(case when coalesce(d.make, '') <> '' and coalesce(d.stock_number, '') <> '' then coalesce(d.front_gross, 0) * dp.split_pct else 0 end), 0) as total_commissionable_gross from review_reps rr join manual_rules mr on mr.rule_id = rr.rule_id left join public.deal_participants dp on dp.employee_id = rr.employee_id left join public.sales_deals d on d.id = dp.deal_id and date_trunc('month', d.contract_date)::date = rr.month group by rr.rule_id, rr.month, rr.store_id, rr.brand, rr.label, rr.pct, rr.flat_amount, rr.employee_id, rr.rep, rr.dealer), with_adjustments as (select rm.*, a.id as adjustment_id, a.id is not null as approved from rep_metrics rm left join lateral (select a1.id from public.adjustments a1 join public.enhancer_rules er on er.id = a1.rule_id where a1.employee_id = rm.employee_id and a1.month = rm.month and a1.category = 'enhancer' and er.metric = 'manual' and er.brand = rm.brand and er.label = rm.label and er.pct is not distinct from rm.pct and er.flat_amount is not distinct from rm.flat_amount order by a1.created_at desc, a1.id desc limit 1) a on true) select rule_id, month, store_id, brand, label, pct, flat_amount, employee_id, rep, dealer, brand_front_gross, total_commissionable_gross, round(case when flat_amount is not null then flat_amount else coalesce(pct, 0) * total_commissionable_gross / 100 end, 2) as proposed_amount, approved, adjustment_id from with_adjustments;
